export const getUsers = async () => {
    async function ff() {
        const request = await fetch("http://localhost:5000/api/users", {
            headers: {
                method: "GET",
                //@ts-ignore
                authorisation: JSON.parse(localStorage.getItem("user")).accessToken,
            }
        })
        return request;
    }
    const request = await ff();
    if (request.status === 401) {
        const Freshrequest = await fetch("http://localhost:5000/api/refresh", {
            method: "GET",
            credentials: "include",
        })
        const res = await Freshrequest.json();
        localStorage.setItem("user", JSON.stringify(res));
        const request = await ff();
        return await request.json();
    }
    return await request.json();
}
